const EACH_IMAGE_MAX_SCREEN_TIME_MS = $('get all workflow params').first().json.eachVisualMaxScreenTimeMs;

// 3) “Мягкий перелёт” — ЗАПРЕЩЕН (строго не выходим за max)
const SOFT_OVERFLOW_MS = 0;

// 4) Какие ключи использовать в RAW_SEGMENTS
const TEXT_KEY   = 'text';
const START_KEYS = ['start_ms', 'start'];
const END_KEYS   = ['end_ms', 'end'];

// 5) Единицы времени
const TIME_UNIT = 'auto'; // 'auto' | 'ms' | 's'

// 6) Общая длительность трека (в мс). Если не найдём — возьмём max(end_ms) после нормализации.
const TOTAL_DUR_MS = (() => {
  try {
    const j = $('get start/end ms of each scentance from transcript1').first().json;

    const candidates = [
      j.total_dur_ms,
      j.totalDurMs,
      j.total_duration_ms,
      (Number(j.total_duration_sec) * 1000),
      (Number(j.meta?.progress?.total_duration_sec) * 1000),
      (Number(j.meta?.total_duration_sec) * 1000),
    ];

    for (const c of candidates) {
      const n = Number(c);
      if (Number.isFinite(n) && n > 0) return Math.round(n);
    }
  } catch (_) {}

  return null;
})();


// ===============================
// 🔧 Implementation
// ===============================

function cleanText(s) {
  return String(s ?? "")
    .replace(/\r?\n/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function pickFirst(obj, keys) {
  for (const k of keys) {
    if (obj && obj[k] != null) return obj[k];
  }
  return null;
}

function toNumber(x) {
  const n = typeof x === "number" ? x : parseFloat(String(x));
  return Number.isFinite(n) ? n : null;
}

// Нормализация start/end в МС (а не только durMs)
function normalizeStartEndMs(rawSeg) {
  // 1) start_ms/end_ms -> считаем что это ms
  const sMs = toNumber(rawSeg?.start_ms);
  const eMs = toNumber(rawSeg?.end_ms);
  if (sMs != null && eMs != null) {
    const start = Math.max(0, Math.round(sMs));
    const end = Math.max(start, Math.round(eMs));
    return { startMs: start, endMs: end };
  }

  // 2) start/end -> auto/ms/s
  const s = toNumber(rawSeg?.start);
  const e = toNumber(rawSeg?.end);
  if (s == null || e == null) return { startMs: 0, endMs: 0 };

  let factor = 1;
  if (TIME_UNIT === 's') factor = 1000;
  else if (TIME_UNIT === 'ms') factor = 1;
  else {
    const diff = e - s;
    const looksLikeSeconds = diff > 0 && diff <= 120 && e <= 20000;
    factor = looksLikeSeconds ? 1000 : 1;
  }

  const start = Math.max(0, Math.round(s * factor));
  const end = Math.max(start, Math.round(e * factor));
  return { startMs: start, endMs: end };
}

// ===============================
// ✅ GAP FILL LOGIC
// ===============================
function fillGapsInPlace(segs, totalDurMs) {
  if (!Array.isArray(segs) || segs.length === 0) return { totalDurMs: totalDurMs ?? 0 };

  segs.sort((a, b) => (a.startMs - b.startMs) || (a._origIndex - b._origIndex));

  if (segs[0].startMs > 0) segs[0].startMs = 0;
  if (segs[0].startMs < 0) segs[0].startMs = 0;
  if (segs[0].endMs < segs[0].startMs) segs[0].endMs = segs[0].startMs;

  if (!Number.isFinite(totalDurMs) || totalDurMs == null || totalDurMs <= 0) {
    let mx = 0;
    for (const s of segs) mx = Math.max(mx, s.endMs);
    totalDurMs = mx;
  } else {
    totalDurMs = Math.max(0, Math.round(totalDurMs));
  }

  for (let i = 0; i < segs.length - 1; i++) {
    const cur = segs[i];
    const next = segs[i + 1];

    if (cur.startMs < 0) cur.startMs = 0;
    if (next.startMs < 0) next.startMs = 0;

    if (cur.endMs < cur.startMs) cur.endMs = cur.startMs;
    if (next.endMs < next.startMs) next.endMs = next.startMs;

    let desiredEnd = next.startMs - 1;
    if (desiredEnd < cur.startMs) desiredEnd = cur.startMs;
    cur.endMs = desiredEnd;

    if (cur.endMs < cur.startMs) cur.endMs = cur.startMs;
  }

  const last = segs[segs.length - 1];
  if (last.startMs < 0) last.startMs = 0;
  if (last.endMs < last.startMs) last.endMs = last.startMs;

  if (last.endMs < totalDurMs) last.endMs = totalDurMs;
  if (last.endMs < last.startMs) last.endMs = last.startMs;

  return { totalDurMs };
}

// --- границы предложений ---
const END_CHARS = new Set([".", "!", "?", "…", "。", "！", "？"]);
const CLOSERS = new Set(['"', "”", "’", "'", ")", "]", "}", "»", "›", "）", "】", "』", "」"]);

const ABBREV = new Set([
  // EN
  "mr","mrs","ms","mx","dr","prof","sr","jr","st","mt","ft","vs",
  "etc","eg","ie","fig","eq","ref","refs","no","nos","dept","inc","ltd","corp","co","bros",
  "est","misc","approx","appt","avg","min","max","temp","vol","ch","sec","pp","p",
  "jan","feb","mar","apr","may","jun","jul","aug","sep","sept","oct","nov","dec",
  "am","pm","a.m","p.m","u.s","u.k","e.u","u.n",

  // RU
  "г","гг","ул","д","кв","стр","рис","пр","просп","наб","бул","пер","пл","пос","обл","р-н",
  "им","акад","доц","проф","см","т.д","т.п","и т.д","и т.п","др",
  "мин","сек","ч","мес","гл","ст","пп","п","млн","млрд","тыс","руб","коп",

  // PL
  "np","itp","itd","m.in","tzn","tj","wg","ok","nr","ul","al","pl","r",
  "godz","min","sek","str","rys","tab","rozdz","pkt","ppkt",
  "dr","hab","mgr","inz","prof",

  // CZ
  "např","napr","tzv","atd","apod","tj","tzn","cl","odst","str","obr","tab","kap",
  "ing","mgr","mudr","judr","phdr","bc","dis",

  // SP (ES)
  "sr","sra","srta","dr","dra","ud","uds","pag","pags","num","nro",
  "aprox","etc","av","pto","dpto","art","cap","eeuu",

  // IT
  "sig","sigg","sigra","sigre","dr","dott","dssa","ing","avv","prof",
  "pag","pagg","num","art","cap","ecc","ca","circa","vle","pza","pzza","cso",

  // FR
  "m","mm","mme","mlle","mlles","dr","pr","etc","env","av","bd","st","ste",
  "no","num","art","chap","pag","tel","tva",

  // GE (DE)
  "hr","fr","dr","prof","bzw","z.b","zb","bsp","bspw","usw","vgl","ca",
  "d.h","dh","u.a","ua","u.ä","ue","str","nr","s","abb","ggf","dipl","ing","dipl-ing",

  // SW
  "bl.a","bla","t.ex","tex","dvs","m.fl","mfl","m.m","mm","osv",
  "ca","nr","sid","kap","fig","kl","dr","prof","ing","fru","herr",

  // HE
  "דר","פרופ","גב","מר","מס","עמ","וכו","לדוג","רח","טל","סע","פרק"
]);


function isLetterOrDigit(ch) {
  return /[0-9A-Za-zÀ-ÖØ-öø-ÿА-Яа-яЁё]/.test(ch);
}

function isAbbrevDot(text, dotPos) {
  let i = dotPos - 1;
  while (i >= 0 && text[i] === " ") i--;

  const end = i + 1;
  while (i >= 0 && (isLetterOrDigit(text[i]) || text[i] === "-" )) i--;
  const start = i + 1;

  const word = text.slice(start, end).toLowerCase();
  if (!word) return false;
  if (word.length === 1) return true;
  if (ABBREV.has(word)) return true;

  const lookback = text.slice(Math.max(0, start - 4), dotPos + 1).toLowerCase();
  if (lookback.includes(".") && lookback.length <= 6) return true;
  return false;
}

function findSentenceBoundaries(text) {
  const out = [];
  const n = text.length;

  for (let i = 0; i < n; i++) {
    const ch = text[i];
    if (!END_CHARS.has(ch)) continue;

    let j = i;
    while (j + 1 < n && END_CHARS.has(text[j + 1])) j++;

    if (text[j] === "." && isAbbrevDot(text, j)) {
      i = j;
      continue;
    }

    let k = j + 1;
    while (k < n && CLOSERS.has(text[k])) k++;

    if (k === n || /\s/.test(text[k])) out.push(k);
    i = j;
  }
  return out;
}

function lastWhitespaceBefore(text, idx) {
  for (let i = Math.min(idx, text.length - 1); i >= 0; i--) {
    if (/\s/.test(text[i])) return i;
  }
  return -1;
}

function firstWhitespaceAfter(text, idx) {
  for (let i = Math.max(0, idx); i < text.length; i++) {
    if (/\s/.test(text[i])) return i;
  }
  return -1;
}

// ===============================
// ✅ STRICT MIN/MAX REBALANCE PATCH
// ===============================

function splitDurStrict(totalDur, minMs, maxMs) {
  const total = Math.max(0, Math.round(totalDur));
  if (total === 0) return [];
  if (total >= minMs && total <= maxMs) return [total];

  // Можно ли сделать все части в [min..max]
  const nMin = Math.ceil(total / maxMs);
  const nMax = Math.floor(total / minMs);

  if (nMin <= nMax && nMin > 0) {
    const n = nMin;
    const base = Math.floor(total / n);
    let rem = total - base * n;
    const out = Array(n).fill(base);
    for (let i = 0; i < n && rem > 0; i++, rem--) out[i]++;
    return out;
  }

  // Иначе строго выполнить диапазон невозможно — режем по max, хвост оставляем
  const out = [];
  let rem = total;
  while (rem > maxMs) {
    out.push(maxMs);
    rem -= maxMs;
  }
  if (rem > 0) out.push(rem);
  return out;
}

function nearestBoundary(boundaries, minPos, maxPos, idealPos) {
  let best = -1;
  let bestDist = Infinity;
  for (const b of boundaries) {
    if (b < minPos || b > maxPos) continue;
    const d = Math.abs(b - idealPos);
    if (d < bestDist) {
      bestDist = d;
      best = b;
    }
  }
  return best;
}

function splitTextByDurations(text, durations) {
  const t = cleanText(text);
  if (!durations.length) return [];
  if (!t) return durations.map(() => "");
  if (durations.length === 1) return [t];

  const out = [];
  const boundaries = findSentenceBoundaries(t);
  const totalDur = durations.reduce((a, b) => a + b, 0);

  let start = 0;
  let accDur = 0;

  for (let i = 0; i < durations.length - 1; i++) {
    accDur += durations[i];

    let ideal = Math.round((accDur / Math.max(1, totalDur)) * t.length);
    ideal = Math.max(start + 1, Math.min(t.length - 1, ideal));

    const minPos = start + 1;
    const maxPos = t.length - 1;

    let cut = nearestBoundary(boundaries, minPos, maxPos, ideal);

    if (cut < 0) {
      const wsLeft = lastWhitespaceBefore(t, ideal);
      const wsRight = firstWhitespaceAfter(t, ideal);

      const leftOk = wsLeft >= minPos && wsLeft <= maxPos;
      const rightOk = wsRight >= minPos && wsRight <= maxPos;

      if (leftOk && rightOk) {
        cut = (Math.abs(wsLeft - ideal) <= Math.abs(wsRight - ideal)) ? wsLeft + 1 : wsRight + 1;
      } else if (leftOk) {
        cut = wsLeft + 1;
      } else if (rightOk) {
        cut = wsRight + 1;
      } else {
        cut = ideal;
      }
    }

    cut = Math.max(minPos, Math.min(maxPos, cut));
    out.push(cleanText(t.slice(start, cut)));
    start = cut;
  }

  out.push(cleanText(t.slice(start)));
  return out;
}

function splitPartStrict(part, minMs, maxMs) {
  const dur = Math.max(0, Math.round(part?.meta?.durMs || 0));
  if (dur <= 0) return [];

  const durs = splitDurStrict(dur, minMs, maxMs);
  const texts = splitTextByDurations(part?.text || "", durs);

  return durs.map((d, i) => ({
    text: cleanText(texts[i] || ""),
    meta: { durMs: d }
  }));
}

function mergeParts(a, b) {
  const ta = cleanText(a?.text || "");
  const tb = cleanText(b?.text || "");
  return {
    text: cleanText((ta && tb) ? (ta + " " + tb) : (ta || tb)),
    meta: {
      durMs: Math.max(0, Math.round((a?.meta?.durMs || 0) + (b?.meta?.durMs || 0)))
    }
  };
}

function rebalancePartsStrict(inputParts, minMs, maxMs) {
  let parts = (Array.isArray(inputParts) ? inputParts : [])
    .map(p => ({
      text: cleanText(p?.text || ""),
      meta: { durMs: Math.max(0, Math.round(p?.meta?.durMs || 0)) }
    }))
    .filter(p => p.meta.durMs > 0);

  if (!parts.length) return [];

  for (let iter = 0; iter < 300; iter++) {
    let changed = false;

    // 1) Все > max режем сразу
    let next = [];
    for (const p of parts) {
      if (p.meta.durMs > maxMs) {
        next.push(...splitPartStrict(p, minMs, maxMs));
        changed = true;
      } else {
        next.push(p);
      }
    }
    parts = next;

    // 2) Ищем первый кусок < min
    const shortIdx = parts.findIndex(p => p.meta.durMs < minMs);
    if (shortIdx === -1) {
      if (!changed) break;
      continue;
    }

    if (parts.length === 1) break; // total < min — неизбежно

    const leftIdx = shortIdx - 1;
    const rightIdx = shortIdx + 1;
    const cur = parts[shortIdx];

    let pickLeft = false;
    if (leftIdx < 0) {
      pickLeft = false;
    } else if (rightIdx >= parts.length) {
      pickLeft = true;
    } else {
      const leftDur = parts[leftIdx].meta.durMs + cur.meta.durMs;
      const rightDur = parts[rightIdx].meta.durMs + cur.meta.durMs;

      const leftOver = Math.max(0, leftDur - maxMs);
      const rightOver = Math.max(0, rightDur - maxMs);

      if (leftOver !== rightOver) {
        pickLeft = leftOver < rightOver;
      } else {
        const target = (minMs + maxMs) / 2;
        pickLeft = Math.abs(leftDur - target) <= Math.abs(rightDur - target);
      }
    }

    if (pickLeft) {
      parts[leftIdx] = mergeParts(parts[leftIdx], cur);
      parts.splice(shortIdx, 1);
    } else {
      parts[rightIdx] = mergeParts(cur, parts[rightIdx]);
      parts.splice(shortIdx, 1);
    }

    changed = true;
    if (!changed) break;
  }

  // Финальный защитный проход по max
  const final = [];
  for (const p of parts) {
    if (p.meta.durMs <= maxMs) final.push(p);
    else final.push(...splitPartStrict(p, minMs, maxMs));
  }

  return final;
}

// ===============================
// 🚀 Core splitter (STRICT MAX + STRICT MIN/MAX PATCH)
// ===============================
function splitByMinMax(rawSegments, cfg) {
  let { minMs, maxMs, softOverflowMs, totalDurMs } = cfg;

  if (!Number.isFinite(minMs) || minMs <= 0) minMs = 2500;
  if (!Number.isFinite(maxMs) || maxMs <= 0) maxMs = 4500;
  if (minMs > maxMs) [minMs, maxMs] = [maxMs, minMs];

  softOverflowMs = 0;
  const hardMaxMs = maxMs;

  // 1) нормализуем сегменты: text + startMs/endMs
  const segs = (Array.isArray(rawSegments) ? rawSegments : [])
    .map((seg, i) => {
      const text = cleanText(seg?.[TEXT_KEY] ?? seg?.text ?? seg?.transcript ?? seg?.caption ?? "");
      const se = normalizeStartEndMs({
        start_ms: seg?.start_ms ?? pickFirst(seg, START_KEYS),
        end_ms:   seg?.end_ms   ?? pickFirst(seg, END_KEYS),
        start:    seg?.start    ?? pickFirst(seg, START_KEYS),
        end:      seg?.end      ?? pickFirst(seg, END_KEYS),
      });

      return {
        _origIndex: i,
        text,
        startMs: se.startMs,
        endMs: se.endMs,
      };
    })
    .filter(s => s.text);

  // 2) заполняем пробелы/убираем перекрытия по start/end
  const filled = fillGapsInPlace(segs, totalDurMs);
  totalDurMs = filled.totalDurMs;

  // 3) для сборки частей используем durMs = end-start (как в оригинале)
  const segments = segs.map(s => ({
    text: s.text,
    durMs: Math.max(0, s.endMs - s.startMs),
  }));

  // 4) Draft split: соблюдаем max, дальше строгий ребаланс
  const draftParts = [];

  function pushPart(txt, dur) {
    const t = cleanText(txt);
    if (!t) return;

    const d = Math.max(0, Math.round(dur));
    draftParts.push({
      text: t,
      meta: { durMs: d },
    });
  }

  let bufText = "";
  let bufDurMs = 0;

  function cutBufferStrict() {
    const t = bufText;
    const totalChars = t.length;

    if (!totalChars || bufDurMs <= 0) {
      pushPart(t, bufDurMs);
      bufText = "";
      bufDurMs = 0;
      return true;
    }

    const denom = Math.max(1, bufDurMs);

    let maxChar = Math.floor(totalChars * (maxMs / denom));
    maxChar = Math.max(1, Math.min(totalChars - 1, maxChar));

    let minChar = Math.floor(totalChars * (minMs / denom));
    minChar = Math.max(0, Math.min(maxChar, minChar));

    const boundaries = findSentenceBoundaries(t);
    let cutIdx = -1;

    // 1) граница в [minChar..maxChar]
    for (let i = boundaries.length - 1; i >= 0; i--) {
      const b = boundaries[i];
      if (b >= minChar && b <= maxChar) { cutIdx = b; break; }
    }

    // 2) поздняя граница <= maxChar
    if (cutIdx < 0) {
      for (let i = boundaries.length - 1; i >= 0; i--) {
        const b = boundaries[i];
        if (b <= maxChar) { cutIdx = b; break; }
      }
    }

    // 3) пробел <= maxChar
    if (cutIdx < 0) {
      const ws = lastWhitespaceBefore(t, maxChar);
      if (ws > 0) cutIdx = ws + 1;
    }

    // 4) иначе — ровно maxChar
    if (cutIdx < 1 || cutIdx >= totalChars) cutIdx = maxChar;

    const leftRaw = t.slice(0, cutIdx);
    const rightRaw = t.slice(cutIdx);

    const leftText = cleanText(leftRaw);
    const rightText = cleanText(rightRaw);

    const leftRatio = cutIdx / Math.max(1, totalChars);
    let leftDur = Math.floor(bufDurMs * leftRatio);
    if (leftDur > maxMs) leftDur = maxMs;
    if (leftDur < 0) leftDur = 0;

    const rightDur = Math.max(0, bufDurMs - leftDur);

    pushPart(leftText, leftDur);
    bufText = rightText;
    bufDurMs = rightDur;

    return true;
  }

  for (const seg of segments) {
    bufText = bufText ? (bufText + " " + seg.text) : seg.text;
    bufDurMs += seg.durMs;

    while (bufText && bufDurMs > hardMaxMs) {
      cutBufferStrict();
      if (bufDurMs < minMs) break;
    }
  }

  if (bufText) {
    while (bufText && bufDurMs > hardMaxMs) {
      cutBufferStrict();
      if (bufDurMs < minMs) break;
    }
    if (bufText) pushPart(bufText, bufDurMs);
  }

  // 5) Патч: ребалансим, чтобы durMs были в [min..max], когда это возможно
  const strictParts = rebalancePartsStrict(draftParts, minMs, maxMs);

  // 6) Восстанавливаем ВСЕ поля как в оригинале
  const parts = strictParts.map((p, i) => {
    const t = cleanText(p.text);
    return {
      partIndex: i,
      text: t,
      meta: {
        durMs: Math.max(0, Math.round(p.meta.durMs || 0)),
        charCount: t.length,
      },
    };
  });

  return {
    parts,
    minMs,
    maxMs,
    softOverflowMs,
    hardMaxMs,
    totalDurMs,
  };
}

// ===============================
// ✅ Run
// ===============================
const result = splitByMinMax(RAW_SEGMENTS, {
  minMs: EACH_IMAGE_MIN_SCREEN_TIME_MS,
  maxMs: EACH_IMAGE_MAX_SCREEN_TIME_MS,
  softOverflowMs: SOFT_OVERFLOW_MS,
  totalDurMs: TOTAL_DUR_MS,
});

return [
  {
    json: {
      parts: result.parts,
      totalDurMs: result.totalDurMs,
      eachImageMinScreenTimeMs: result.minMs,
      eachImageMaxScreenTimeMs: result.maxMs,
      hardMaxMs: result.hardMaxMs,
    }
  }
];

